    pub fn version(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("version", .{});
        return try self.execute(qb, []const u8);
    }

    pub fn execute(self: *Client, query_builder: *QueryBuilder, comptime ResponseType: type) !ResponseType {
        _ = self;
        _ = query_builder;
        return error.Unimplemented;
    }
};

