/// A comparison between two directories representing changes that can be applied.
pub const Changeset = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// Files and directories that were added in the newer directory.
    pub fn addedPaths(self: *@This()) ![]const []const u8 {
        const qb = try self.query_builder.selection("addedPaths", .{});
        return try self.client.execute(qb, []const []const u8);
    }

    /// The newer/upper snapshot.
    pub fn after(self: *@This()) !Directory {
        const qb = try self.query_builder.selection("after", .{});
        return Directory{ .query_builder = qb, .client = self.client };
    }

    /// Return a Git-compatible patch of the changes
    pub fn asPatch(self: *@This()) !File {
        const qb = try self.query_builder.selection("asPatch", .{});
        return File{ .query_builder = qb, .client = self.client };
    }

    /// The older/lower snapshot to compare against.
    pub fn before(self: *@This()) !Directory {
        const qb = try self.query_builder.selection("before", .{});
        return Directory{ .query_builder = qb, .client = self.client };
    }

    /// Structured per-path diff statistics (kind and line counts) for this changeset.
    pub fn diffStats(self: *@This()) ![]const DiffStat {
        const qb = try self.query_builder.selection("diffStats", .{});
        const ids = try self.client.execute(qb, []const DiffStatID);
        var results = try self.client.allocator.alloc(DiffStat, ids.len);
        for (ids, 0..) |id_val, i| {
            results[i] = try self.client.loadDiffStatFromID(id_val);
        }
        return results;
    }

    /// Applies the diff represented by this changeset to a path on the host.
    pub fn @"export"(self: *@This(), path_arg: []const u8) ![]const u8 {
        const qb = try self.query_builder.selection("export", .{
            .path = path_arg,
        });
        return try self.client.execute(qb, []const u8);
    }

    /// A unique identifier for this Changeset.
    pub fn id(self: *@This()) !ChangesetID {
        const qb = try self.query_builder.selection("id", .{});
        return try self.client.execute(qb, ChangesetID);
    }

    /// Returns true if the changeset is empty (i.e. there are no changes).
    pub fn isEmpty(self: *@This()) !bool {
        const qb = try self.query_builder.selection("isEmpty", .{});
        return try self.client.execute(qb, bool);
    }

    /// Return a snapshot containing only the created and modified files
    pub fn layer(self: *@This()) !Directory {
        const qb = try self.query_builder.selection("layer", .{});
        return Directory{ .query_builder = qb, .client = self.client };
    }

    /// Files and directories that existed before and were updated in the newer directory.
    pub fn modifiedPaths(self: *@This()) ![]const []const u8 {
        const qb = try self.query_builder.selection("modifiedPaths", .{});
        return try self.client.execute(qb, []const []const u8);
    }

    /// Files and directories that were removed. Directories are indicated by a trailing slash, and their child paths are not included.
    pub fn removedPaths(self: *@This()) ![]const []const u8 {
        const qb = try self.query_builder.selection("removedPaths", .{});
        return try self.client.execute(qb, []const []const u8);
    }

    /// Force evaluation in the engine.
    pub fn sync(self: *@This()) !ChangesetID {
        const qb = try self.query_builder.selection("sync", .{});
        const id_val = try self.client.execute(qb, ChangesetID);
        return try self.client.loadChangesetFromID(id_val);
    }

    /// Add changes to an existing changeset
    ///
    /// By default the operation will fail in case of conflicts, for instance a file modified in both changesets. The behavior can be adjusted using onConflict argument
    pub fn withChangeset(self: *@This(), changes_arg: ChangesetID, options: struct {
        onConflict: ?ChangesetMergeConflict = null,
    }) !Changeset {
        const qb = try self.query_builder.selection("withChangeset", .{
            .changes = changes_arg,
            .onConflict = options.onConflict,
        });
        return Changeset{ .query_builder = qb, .client = self.client };
    }

    /// Add changes from multiple changesets using git octopus merge strategy
    ///
    /// This is more efficient than chaining multiple withChangeset calls when merging many changesets.
    ///
    /// Only FAIL and FAIL_EARLY conflict strategies are supported (octopus merge cannot use -X ours/theirs).
    pub fn withChangesets(self: *@This(), changes_arg: []const ChangesetID, options: struct {
        onConflict: ?ChangesetsMergeConflict = null,
    }) !Changeset {
        const qb = try self.query_builder.selection("withChangesets", .{
            .changes = changes_arg,
            .onConflict = options.onConflict,
        });
        return Changeset{ .query_builder = qb, .client = self.client };
    }
};

