/// An OCI-compatible container, also known as a Docker container.
pub const Container = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// Turn the container into a Service.
    ///
    /// Be sure to set any exposed ports before this conversion.
    pub fn asService(self: *@This(), options: struct {
        args: ?[]const []const u8 = null,
        useEntrypoint: ?bool = null,
        experimentalPrivilegedNesting: ?bool = null,
        insecureRootCapabilities: ?bool = null,
        expand: ?bool = null,
        noInit: ?bool = null,
    }) !Service {
        const qb = try self.query_builder.selection("asService", .{
            .args = options.args,
            .useEntrypoint = options.useEntrypoint,
            .experimentalPrivilegedNesting = options.experimentalPrivilegedNesting,
            .insecureRootCapabilities = options.insecureRootCapabilities,
            .expand = options.expand,
            .noInit = options.noInit,
        });
        return Service{ .query_builder = qb, .client = self.client };
    }

    /// Package the container state as an OCI image, and return it as a tar archive
    pub fn asTarball(self: *@This(), options: struct {
        platformVariants: ?[]const ContainerID = null,
        forcedCompression: ?ImageLayerCompression = null,
        mediaTypes: ?ImageMediaTypes = null,
    }) !File {
        const qb = try self.query_builder.selection("asTarball", .{
            .platformVariants = options.platformVariants,
            .forcedCompression = options.forcedCompression,
            .mediaTypes = options.mediaTypes,
        });
        return File{ .query_builder = qb, .client = self.client };
    }

    /// The combined buffered standard output and standard error stream of the last executed command
    ///
    /// Returns an error if no command was executed
    pub fn combinedOutput(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("combinedOutput", .{});
        return try self.client.execute(qb, []const u8);
    }

    /// Return the container's default arguments.
    pub fn defaultArgs(self: *@This()) ![]const []const u8 {
        const qb = try self.query_builder.selection("defaultArgs", .{});
        return try self.client.execute(qb, []const []const u8);
    }

    /// Retrieve a directory from the container's root filesystem
    ///
    /// Mounts are included.
    pub fn directory(self: *@This(), path_arg: []const u8, options: struct {
        expand: ?bool = null,
    }) !Directory {
        const qb = try self.query_builder.selection("directory", .{
            .path = path_arg,
            .expand = options.expand,
