/// Reflective module API provided to functions at runtime.
pub const CurrentModule = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// The dependencies of the module.
    pub fn dependencies(self: *@This()) ![]const Module {
        const qb = try self.query_builder.selection("dependencies", .{});
        const ids = try self.client.execute(qb, []const ModuleID);
        var results = try self.client.allocator.alloc(Module, ids.len);
        for (ids, 0..) |id_val, i| {
            results[i] = try self.client.loadModuleFromID(id_val);
        }
        return results;
    }

    /// The generated files and directories made on top of the module source's context directory.
    pub fn generatedContextDirectory(self: *@This()) !Directory {
        const qb = try self.query_builder.selection("generatedContextDirectory", .{});
        return Directory{ .query_builder = qb, .client = self.client };
    }

    /// Return all generators defined by the module
    pub fn generators(self: *@This(), options: struct {
        include: ?[]const []const u8 = null,
    }) !GeneratorGroup {
        const qb = try self.query_builder.selection("generators", .{
            .include = options.include,
        });
        return GeneratorGroup{ .query_builder = qb, .client = self.client };
    }

    /// A unique identifier for this CurrentModule.
    pub fn id(self: *@This()) !CurrentModuleID {
        const qb = try self.query_builder.selection("id", .{});
        return try self.client.execute(qb, CurrentModuleID);
    }

    /// The name of the module being executed in
    pub fn name(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("name", .{});
        return try self.client.execute(qb, []const u8);
    }

    /// The directory containing the module's source code loaded into the engine (plus any generated code that may have been created).
    pub fn source(self: *@This()) !Directory {
        const qb = try self.query_builder.selection("source", .{});
        return Directory{ .query_builder = qb, .client = self.client };
    }

    /// Load a directory from the module's scratch working directory, including any changes that may have been made to it during module function execution.
    pub fn workdir(self: *@This(), path_arg: []const u8, options: struct {
        exclude: ?[]const []const u8 = null,
        include: ?[]const []const u8 = null,
        gitignore: ?bool = null,
    }) !Directory {
        const qb = try self.query_builder.selection("workdir", .{
            .path = path_arg,
            .exclude = options.exclude,
            .include = options.include,
            .gitignore = options.gitignore,
        });
        return Directory{ .query_builder = qb, .client = self.client };
    }

    /// Load a file from the module's scratch working directory, including any changes that may have been made to it during module function execution.Load a file from the module's scratch working directory, including any changes that may have been made to it during module function execution.
    pub fn workdirFile(self: *@This(), path_arg: []const u8) !File {
        const qb = try self.query_builder.selection("workdirFile", .{
            .path = path_arg,
        });
        return File{ .query_builder = qb, .client = self.client };
    }
};

