/// A collection of environment variables.
pub const EnvFile = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// Return as a file
    pub fn asFile(self: *@This()) !File {
        const qb = try self.query_builder.selection("asFile", .{});
        return File{ .query_builder = qb, .client = self.client };
    }

    /// Check if a variable exists
    pub fn exists(self: *@This(), name_arg: []const u8) !bool {
        const qb = try self.query_builder.selection("exists", .{
            .name = name_arg,
        });
        return try self.client.execute(qb, bool);
    }

    /// Lookup a variable (last occurrence wins) and return its value, or an empty string
    pub fn get(self: *@This(), name_arg: []const u8, options: struct {
        raw: ?bool = null,
    }) ![]const u8 {
        const qb = try self.query_builder.selection("get", .{
            .name = name_arg,
            .raw = options.raw,
        });
        return try self.client.execute(qb, []const u8);
    }

    /// A unique identifier for this EnvFile.
    pub fn id(self: *@This()) !EnvFileID {
        const qb = try self.query_builder.selection("id", .{});
        return try self.client.execute(qb, EnvFileID);
    }

    /// Filters variables by prefix and removes the pref from keys. Variables without the prefix are excluded. For example, with the prefix "MY_APP_" and variables: MY_APP_TOKEN=topsecret MY_APP_NAME=hello FOO=bar the resulting environment will contain: TOKEN=topsecret NAME=hello
    pub fn namespace(self: *@This(), prefix: []const u8) !EnvFile {
        const qb = try self.query_builder.selection("namespace", .{
            .prefix = prefix,
        });
        return EnvFile{ .query_builder = qb, .client = self.client };
    }

    /// Return all variables
    pub fn variables(self: *@This(), options: struct {
        raw: ?bool = null,
    }) ![]const EnvVariable {
        const qb = try self.query_builder.selection("variables", .{
            .raw = options.raw,
        });
        const ids = try self.client.execute(qb, []const EnvVariableID);
        var results = try self.client.allocator.alloc(EnvVariable, ids.len);
        for (ids, 0..) |id_val, i| {
            results[i] = try self.client.loadEnvVariableFromID(id_val);
        }
        return results;
    }

    /// Add a variable
    pub fn withVariable(self: *@This(), name_arg: []const u8, value: []const u8) !EnvFile {
        const qb = try self.query_builder.selection("withVariable", .{
            .name = name_arg,
            .value = value,
        });
        return EnvFile{ .query_builder = qb, .client = self.client };
    }

    /// Remove all occurrences of the named variable
    pub fn withoutVariable(self: *@This(), name_arg: []const u8) !EnvFile {
        const qb = try self.query_builder.selection("withoutVariable", .{
            .name = name_arg,
        });
        return EnvFile{ .query_builder = qb, .client = self.client };
    }
};

