/// A file.
pub const File = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// Parse as an env file
    pub fn asEnvFile(self: *@This(), options: struct {
        expand: ?bool = null,
    }) !EnvFile {
        const qb = try self.query_builder.selection("asEnvFile", .{
            .expand = options.expand,
        });
        return EnvFile{ .query_builder = qb, .client = self.client };
    }

    /// Parse the file contents as JSON.
    pub fn asJSON(self: *@This()) !JSONValue {
        const qb = try self.query_builder.selection("asJSON", .{});
        return JSONValue{ .query_builder = qb, .client = self.client };
    }

    /// Change the owner of the file recursively.
    pub fn chown(self: *@This(), owner: []const u8) !File {
        const qb = try self.query_builder.selection("chown", .{
            .owner = owner,
        });
        return File{ .query_builder = qb, .client = self.client };
    }

    /// Retrieves the contents of the file.
    pub fn contents(self: *@This(), options: struct {
        offsetLines: ?i32 = null,
        limitLines: ?i32 = null,
    }) ![]const u8 {
        const qb = try self.query_builder.selection("contents", .{
            .offsetLines = options.offsetLines,
            .limitLines = options.limitLines,
        });
        return try self.client.execute(qb, []const u8);
    }

    /// Return the file's digest. The format of the digest is not guaranteed to be stable between releases of Dagger. It is guaranteed to be stable between invocations of the same Dagger engine.
    pub fn digest(self: *@This(), options: struct {
        excludeMetadata: ?bool = null,
    }) ![]const u8 {
        const qb = try self.query_builder.selection("digest", .{
            .excludeMetadata = options.excludeMetadata,
        });
        return try self.client.execute(qb, []const u8);
    }

    /// Writes the file to a file path on the host.
    pub fn @"export"(self: *@This(), path_arg: []const u8, options: struct {
        allowParentDirPath: ?bool = null,
    }) ![]const u8 {
        const qb = try self.query_builder.selection("export", .{
            .path = path_arg,
            .allowParentDirPath = options.allowParentDirPath,
        });
        return try self.client.execute(qb, []const u8);
    }

    /// A unique identifier for this File.
    pub fn id(self: *@This()) !FileID {
        const qb = try self.query_builder.selection("id", .{});
        return try self.client.execute(qb, FileID);
    }

    /// Retrieves the name of the file.
    pub fn name(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("name", .{});
        return try self.client.execute(qb, []const u8);
    }

    /// Searches for content matching the given regular expression or literal string.
    ///
    /// Uses Rust regex syntax; escape literal ., [, ], {, }, | with backslashes.
    pub fn search(self: *@This(), pattern: []const u8, options: struct {
        literal: ?bool = null,
        multiline: ?bool = null,
        dotall: ?bool = null,
        insensitive: ?bool = null,
        skipIgnored: ?bool = null,
        skipHidden: ?bool = null,
        filesOnly: ?bool = null,
        limit: ?i32 = null,
        paths: ?[]const []const u8 = null,
        globs: ?[]const []const u8 = null,
    }) ![]const SearchResult {
        const qb = try self.query_builder.selection("search", .{
            .pattern = pattern,
            .literal = options.literal,
            .multiline = options.multiline,
            .dotall = options.dotall,
            .insensitive = options.insensitive,
            .skipIgnored = options.skipIgnored,
            .skipHidden = options.skipHidden,
            .filesOnly = options.filesOnly,
            .limit = options.limit,
            .paths = options.paths,
            .globs = options.globs,
        });
        const ids = try self.client.execute(qb, []const SearchResultID);
        var results = try self.client.allocator.alloc(SearchResult, ids.len);
        for (ids, 0..) |id_val, i| {
            results[i] = try self.client.loadSearchResultFromID(id_val);
        }
        return results;
    }

    /// Retrieves the size of the file, in bytes.
    pub fn size(self: *@This()) !i32 {
        const qb = try self.query_builder.selection("size", .{});
        return try self.client.execute(qb, i32);
    }

    /// Return file status
    pub fn stat(self: *@This()) !?Stat {
        const qb = try self.query_builder.selection("stat", .{});
        return Stat{ .query_builder = qb, .client = self.client };
    }

    /// Force evaluation in the engine.
    pub fn sync(self: *@This()) !FileID {
        const qb = try self.query_builder.selection("sync", .{});
        const id_val = try self.client.execute(qb, FileID);
        return try self.client.loadFileFromID(id_val);
    }

    /// Retrieves this file with its name set to the given name.
    pub fn withName(self: *@This(), name_arg: []const u8) !File {
        const qb = try self.query_builder.selection("withName", .{
            .name = name_arg,
        });
        return File{ .query_builder = qb, .client = self.client };
    }

    /// Retrieves the file with content replaced with the given text.
    ///
    /// If 'all' is true, all occurrences of the pattern will be replaced.
    ///
    /// If 'firstAfter' is specified, only the first match starting at the specified line will be replaced.
    ///
    /// If neither are specified, and there are multiple matches for the pattern, this will error.
    ///
    /// If there are no matches for the pattern, this will error.
    pub fn withReplaced(self: *@This(), search_arg: []const u8, replacement: []const u8, options: struct {
        all: ?bool = null,
        firstFrom: ?i32 = null,
    }) !File {
        const qb = try self.query_builder.selection("withReplaced", .{
            .search = search_arg,
            .replacement = replacement,
            .all = options.all,
            .firstFrom = options.firstFrom,
        });
        return File{ .query_builder = qb, .client = self.client };
    }

    /// Retrieves this file with its created/modified timestamps set to the given time.
    pub fn withTimestamps(self: *@This(), timestamp: i32) !File {
        const qb = try self.query_builder.selection("withTimestamps", .{
            .timestamp = timestamp,
        });
        return File{ .query_builder = qb, .client = self.client };
    }
};

