///
pub const GeneratorGroup = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// The combined changes from the last run of the generators
    ///
    /// If any conflict occurs, for instance if the same file is modified by multiple generators, or if a file is both modified and deleted, an error is raised and the merge of the changesets will failed.
    ///
    /// Set 'continueOnConflicts' flag to force to merge the changes in a 'last write wins' strategy.
    pub fn changes(self: *@This(), options: struct {
        onConflict: ?ChangesetsMergeConflict = null,
    }) !Changeset {
        const qb = try self.query_builder.selection("changes", .{
            .onConflict = options.onConflict,
        });
        return Changeset{ .query_builder = qb, .client = self.client };
    }

    /// A unique identifier for this GeneratorGroup.
    pub fn id(self: *@This()) !GeneratorGroupID {
        const qb = try self.query_builder.selection("id", .{});
        return try self.client.execute(qb, GeneratorGroupID);
    }

    /// Whether the generated changeset from the last run is empty or not
    pub fn isEmpty(self: *@This()) !bool {
        const qb = try self.query_builder.selection("isEmpty", .{});
        return try self.client.execute(qb, bool);
    }

    /// Return a list of individual generators and their details
    pub fn list(self: *@This()) ![]const Generator {
        const qb = try self.query_builder.selection("list", .{});
        const ids = try self.client.execute(qb, []const GeneratorID);
        var results = try self.client.allocator.alloc(Generator, ids.len);
        for (ids, 0..) |id_val, i| {
            results[i] = try self.client.loadGeneratorFromID(id_val);
        }
        return results;
    }

    /// Execute all selected generators
    pub fn run(self: *@This()) !GeneratorGroup {
        const qb = try self.query_builder.selection("run", .{});
        return GeneratorGroup{ .query_builder = qb, .client = self.client };
    }
};

