/// A graphql input type, which is essentially just a group of named args.
/// This is currently only used to represent pre-existing usage of graphql input types
/// in the core API. It is not used by user modules and shouldn't ever be as user
/// module accept input objects via their id rather than graphql input types.
pub const InputTypeDef = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// Static fields defined on this input object, if any.
    pub fn fields(self: *@This()) ![]const FieldTypeDef {
        const qb = try self.query_builder.selection("fields", .{});
        const ids = try self.client.execute(qb, []const FieldTypeDefID);
        var results = try self.client.allocator.alloc(FieldTypeDef, ids.len);
        for (ids, 0..) |id_val, i| {
            results[i] = try self.client.loadFieldTypeDefFromID(id_val);
        }
        return results;
    }

    /// A unique identifier for this InputTypeDef.
    pub fn id(self: *@This()) !InputTypeDefID {
        const qb = try self.query_builder.selection("id", .{});
        return try self.client.execute(qb, InputTypeDefID);
    }

    /// The name of the input object.
    pub fn name(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("name", .{});
        return try self.client.execute(qb, []const u8);
    }
};

