/// A content-addressed service providing TCP connectivity.
pub const Service = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// Retrieves an endpoint that clients can use to reach this container.
    ///
    /// If no port is specified, the first exposed port is used. If none exist an error is returned.
    ///
    /// If a scheme is specified, a URL is returned. Otherwise, a host:port pair is returned.
    pub fn endpoint(self: *@This(), options: struct {
        port: ?i32 = null,
        scheme: ?[]const u8 = null,
    }) ![]const u8 {
        const qb = try self.query_builder.selection("endpoint", .{
            .port = options.port,
            .scheme = options.scheme,
        });
        return try self.client.execute(qb, []const u8);
    }

    /// Retrieves a hostname which can be used by clients to reach this container.
    pub fn hostname(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("hostname", .{});
        return try self.client.execute(qb, []const u8);
    }

    /// A unique identifier for this Service.
    pub fn id(self: *@This()) !ServiceID {
        const qb = try self.query_builder.selection("id", .{});
        return try self.client.execute(qb, ServiceID);
    }

    /// Retrieves the list of ports provided by the service.
    pub fn ports(self: *@This()) ![]const Port {
        const qb = try self.query_builder.selection("ports", .{});
        const ids = try self.client.execute(qb, []const PortID);
        var results = try self.client.allocator.alloc(Port, ids.len);
        for (ids, 0..) |id_val, i| {
            results[i] = try self.client.loadPortFromID(id_val);
        }
        return results;
    }

    /// Start the service and wait for its health checks to succeed.
    ///
    /// Services bound to a Container do not need to be manually started.
    pub fn start(self: *@This()) !ServiceID {
        const qb = try self.query_builder.selection("start", .{});
        const id_val = try self.client.execute(qb, ServiceID);
        return try self.client.loadServiceFromID(id_val);
    }

    /// Stop the service.
    pub fn stop(self: *@This(), options: struct {
        kill: ?bool = null,
    }) !ServiceID {
        const qb = try self.query_builder.selection("stop", .{
            .kill = options.kill,
        });
        const id_val = try self.client.execute(qb, ServiceID);
        return try self.client.loadServiceFromID(id_val);
    }

    /// Forces evaluation of the pipeline in the engine.
    pub fn sync(self: *@This()) !ServiceID {
        const qb = try self.query_builder.selection("sync", .{});
        const id_val = try self.client.execute(qb, ServiceID);
        return try self.client.loadServiceFromID(id_val);
    }

    ///
    pub fn terminal(self: *@This(), options: struct {
        cmd: ?[]const []const u8 = null,
    }) !Service {
        const qb = try self.query_builder.selection("terminal", .{
            .cmd = options.cmd,
        });
        return Service{ .query_builder = qb, .client = self.client };
    }

    /// Creates a tunnel that forwards traffic from the caller's network to this service.
    pub fn up(self: *@This(), options: struct {
        ports: ?[]const PortForward = null,
        random: ?bool = null,
    }) !?void {
        const qb = try self.query_builder.selection("up", .{
            .ports = options.ports,
            .random = options.random,
        });
        _ = try self.client.execute(qb, void);
    }

    /// Configures a hostname which can be used by clients within the session to reach this container.
    pub fn withHostname(self: *@This(), hostname_arg: []const u8) !Service {
        const qb = try self.query_builder.selection("withHostname", .{
            .hostname = hostname_arg,
        });
        return Service{ .query_builder = qb, .client = self.client };
    }
};

