///
pub const Up = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// The description of the service
    pub fn description(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("description", .{});
        return try self.client.execute(qb, []const u8);
    }

    /// A unique identifier for this Up.
    pub fn id(self: *@This()) !UpID {
        const qb = try self.query_builder.selection("id", .{});
        return try self.client.execute(qb, UpID);
    }

    /// Return the fully qualified name of the service
    pub fn name(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("name", .{});
        return try self.client.execute(qb, []const u8);
    }

    /// The original module in which the service has been defined
    pub fn originalModule(self: *@This()) !Module {
        const qb = try self.query_builder.selection("originalModule", .{});
        return Module{ .query_builder = qb, .client = self.client };
    }

    /// The path of the service within its module
    pub fn path(self: *@This()) ![]const []const u8 {
        const qb = try self.query_builder.selection("path", .{});
        return try self.client.execute(qb, []const []const u8);
    }

    /// Execute the service function
    pub fn run(self: *@This()) !Up {
        const qb = try self.query_builder.selection("run", .{});
        return Up{ .query_builder = qb, .client = self.client };
    }
};

///
pub const UpGroup = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// A unique identifier for this UpGroup.
    pub fn id(self: *@This()) !UpGroupID {
        const qb = try self.query_builder.selection("id", .{});
        return try self.client.execute(qb, UpGroupID);
    }

    /// Return a list of individual services and their details
    pub fn list(self: *@This()) ![]const Up {
        const qb = try self.query_builder.selection("list", .{});
        const ids = try self.client.execute(qb, []const UpID);
        var results = try self.client.allocator.alloc(Up, ids.len);
        for (ids, 0..) |id_val, i| {
            results[i] = try self.client.loadUpFromID(id_val);
        }
        return results;
    }

    /// Execute all selected service functions
    pub fn run(self: *@This()) !UpGroup {
        const qb = try self.query_builder.selection("run", .{});
        return UpGroup{ .query_builder = qb, .client = self.client };
    }
};

/// A Dagger workspace detected from the current working directory.
pub const Workspace = struct {
    query_builder: *QueryBuilder,
    client: *Client,

    /// Canonical Dagger address of the workspace directory.
    pub fn address(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("address", .{});
        return try self.client.execute(qb, []const u8);
    }

    /// Return all checks from modules loaded in the workspace.
    pub fn checks(self: *@This(), options: struct {
        include: ?[]const []const u8 = null,
    }) !CheckGroup {
        const qb = try self.query_builder.selection("checks", .{
            .include = options.include,
        });
        return CheckGroup{ .query_builder = qb, .client = self.client };
    }

    /// The client ID that owns this workspace's host filesystem.
    pub fn clientId(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("clientId", .{});
        return try self.client.execute(qb, []const u8);
    }

    /// Path to config.toml relative to the workspace boundary (empty if not initialized).
    pub fn configPath(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("configPath", .{});
        return try self.client.execute(qb, []const u8);
    }

    /// Returns a Directory from the workspace.
    ///
    /// Relative paths resolve from the workspace directory. Absolute paths resolve from the workspace boundary.
    pub fn directory(self: *@This(), path_arg: []const u8, options: struct {
        exclude: ?[]const []const u8 = null,
        include: ?[]const []const u8 = null,
        gitignore: ?bool = null,
    }) !Directory {
        const qb = try self.query_builder.selection("directory", .{
            .path = path_arg,
            .exclude = options.exclude,
            .include = options.include,
            .gitignore = options.gitignore,
        });
        return Directory{ .query_builder = qb, .client = self.client };
    }

    /// Returns a File from the workspace.
    ///
    /// Relative paths resolve from the workspace directory. Absolute paths resolve from the workspace boundary.
    pub fn file(self: *@This(), path_arg: []const u8) !File {
        const qb = try self.query_builder.selection("file", .{
            .path = path_arg,
        });
        return File{ .query_builder = qb, .client = self.client };
    }

    /// Search for a file or directory by walking up from the start path within the workspace.
    ///
    /// Returns the absolute workspace path if found, or null if not found.
    ///
    /// Relative start paths resolve from the workspace directory.
    ///
    /// The search stops at the workspace boundary and will not traverse above it.
    pub fn findUp(self: *@This(), name_arg: []const u8, options: struct {
        from: ?[]const u8 = null,
    }) !?[]const u8 {
        const qb = try self.query_builder.selection("findUp", .{
            .name = name_arg,
            .from = options.from,
        });
        return try self.client.execute(qb, ?[]const u8);
    }

    /// Return all generators from modules loaded in the workspace.
    pub fn generators(self: *@This(), options: struct {
        include: ?[]const []const u8 = null,
    }) !GeneratorGroup {
        const qb = try self.query_builder.selection("generators", .{
            .include = options.include,
        });
        return GeneratorGroup{ .query_builder = qb, .client = self.client };
    }

    /// Whether a config.toml file exists in the workspace.
    pub fn hasConfig(self: *@This()) !bool {
        const qb = try self.query_builder.selection("hasConfig", .{});
        return try self.client.execute(qb, bool);
    }

    /// A unique identifier for this Workspace.
    pub fn id(self: *@This()) !WorkspaceID {
        const qb = try self.query_builder.selection("id", .{});
        return try self.client.execute(qb, WorkspaceID);
    }

    /// Whether .dagger/config.toml exists.
    pub fn initialized(self: *@This()) !bool {
        const qb = try self.query_builder.selection("initialized", .{});
        return try self.client.execute(qb, bool);
    }

    /// Workspace directory path relative to the workspace boundary.
    pub fn path(self: *@This()) ![]const u8 {
        const qb = try self.query_builder.selection("path", .{});
        return try self.client.execute(qb, []const u8);
    }

    /// Return all services from modules loaded in the workspace.
    pub fn services(self: *@This(), options: struct {
        include: ?[]const []const u8 = null,
    }) !UpGroup {
        const qb = try self.query_builder.selection("services", .{
            .include = options.include,
        });
        return UpGroup{ .query_builder = qb, .client = self.client };
    }
};
